Rule.Source:
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Global-Domain-Rule");

  logger.debug("Start Ascension-Global-Domain-Rule");
  String attributeValue = null;
  HashMap domaines = new HashMap();
  List exceptionalMinistry = new ArrayList();

  IdentityService idService = new IdentityService(context);
  Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");

  if(custom != null && custom.get("HealthMinistryDomainMapping") !=null){
    domaines = custom.get("HealthMinistryDomainMapping");
    exceptionalMinistry = custom.get("domainworkitemministry");
    //comment decache //context.decache(custom);
  }

  if(null != identity){

    List<Link> appLinks = null;
    Application app = context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");		
    Application midasApp = context.getObjectByName(Application.class,"Midas Seeker - Provider Onboarding");
    Application mdstaffAppAsc = context.getObjectByName(Application.class,"MDStaff - Ascension");
    Application mdstaffApp = context.getObjectByName(Application.class,"MDStaff - AMITA");
    Application morriseyApp = context.getObjectByName(Application.class,"Morrisey");


    if(null != app && !Util.isEmpty((appLinks = idService.getLinks( identity, app)))){
      attributeValue = appLinks.get(0).getAttribute("SETID_LOCATION");
      if(Util.isNotNullOrEmpty(identity.getStringAttribute("domain")) && Util.isNotNullOrEmpty(identity.getStringAttribute("ministry")) && !Util.isEmpty(exceptionalMinistry) && exceptionalMinistry.contains(identity.getStringAttribute("ministry"))){
        attributeValue = identity.getAttribute("domain");
      }       
      else if(null != domaines && !domaines.isEmpty()){
        for (Map.Entry entry : domaines.entrySet()){  
          if(Util.isNotNullOrEmpty(attributeValue) && Util.nullSafeCaseInsensitiveEq(attributeValue,entry.getKey())){
            attributeValue = entry.getValue();
          }
        }
      }	
    } else if(null != midasApp && !Util.isEmpty(idService.getLinks( identity, midasApp))){ 
      attributeValue = "TNNAS";	
    } else if(null != morriseyApp && !Util.isEmpty(idService.getLinks( identity, morriseyApp))){ 
      attributeValue = "AMITA";								
    } else if(null != mdstaffAppAsc && !Util.isEmpty(appLinks = idService.getLinks( identity, mdstaffAppAsc))){ 
      attributeValue = appLinks.get(0).getAttribute("Ministry_Domain");	     		
    } else if(null != mdstaffApp && !Util.isEmpty(idService.getLinks( identity, mdstaffApp))){ 
      attributeValue = "AMITA";				
    } else if(Util.isNotNullOrEmpty(identity.getAttribute("domain"))){        
      attributeValue = identity.getStringAttribute("domain");
    } 

    if(null != app){
      //comment decache //context.decache(app);
    }
    if(null != midasApp){
      //comment decache //context.decache(midasApp);
    }
    if(null != morriseyApp){
      //comment decache //context.decache(morriseyApp);
    }	
    if(null != mdstaffAppAsc){
      //comment decache //context.decache(mdstaffAppAsc);
    }	
    if(null != mdstaffApp){
      //comment decache //context.decache(mdstaffApp);
    }	
  }
  logger.debug("returning domain :"+ attributeValue);

  return attributeValue;
